/* ── With label (forms) ── */
<div class="dt-input-group">
  <label class="dt-input-label">Label</label>
  <input
    class="dt-input"
    type="text"
    placeholder="Placeholder"
    value={value}
    onChange={e => setValue(e.target.value)}
  />
</div>

/* ── Error state ── */
<div class="dt-input-group">
  <label class="dt-input-label">Label</label>
  <input class="dt-input dt-input--error" type="text" value={value} />
  <span class="dt-input-helper dt-input-helper--error">Formato inválido</span>
</div>

/* ── Without label (filters) ── */
<input
  class="dt-input"
  type="text"
  placeholder="Buscar..."
  value={value}
  onChange={e => setValue(e.target.value)}
/>

/* ── With search icon ── */
<div class="dt-input-wrap">
  <input class="dt-input" type="text" placeholder="Buscar..." />
  <SearchIcon class="dt-input-icon" />
</div>

/* ── Disabled ── */
<input class="dt-input" type="text" value="Valor bloqueado" disabled />

/* ── CSS tokens ── */
.dt-input {
  height: 32px;
  padding: 0 10px;
  border: 1px solid var(--n3);
  border-radius: 6px;
  background: #fff;
  font: 400 14px/20px var(--font-sans);
  color: var(--n7);
  width: 100%;
}
.dt-input::placeholder { color: var(--n6); }
.dt-input:focus {
  outline: none;
  border-color: var(--n5);
  box-shadow: 0 0 0 3px rgba(75,130,250,.18);
}
.dt-input--error { border-color: var(--r6); }
.dt-input:disabled {
  background: var(--n1);
  cursor: not-allowed;
  opacity: .6;
}
.dt-input-label {
  font: 600 12px/16px var(--font-sans);
  color: var(--n7);
  margin-bottom: 4px;
  display: block;
}
.dt-input-helper {
  font: 400 12px/16px var(--font-sans);
  color: var(--n5);
  margin-top: 3px;
}
.dt-input-helper--error { color: var(--r6); }
